_ow_install_module('sim_engine', '"""Exact local port of the orbit_wars engine step (minus comet spawning,\nwhich is seed-hidden and unpredictable anyway).\n\nState is a dict:\n  planets: list of [id, owner, x, y, r, ships, prod]   (mutated copies)\n  fleets:  list of [id, owner, x, y, angle, from_id, ships]\n  next_fleet_id: int\n  step: int                  (current observation step)\n  angular_velocity: float\n  initial: {pid: (ix, iy)}   (initial positions, for rotation)\n  comet_paths: {pid: (path, base_index)}  base_index = path_index at state.step\n"""\nimport math\n\nBOARD = 100.0\nCENTER = 50.0\nSUN_R = 10.0\nROT_LIM = 50.0\nLOG1000 = math.log(1000.0)\n\n\ndef fleet_speed(n, max_speed=6.0):\n    if n <= 1:\n        return 1.0\n    r = math.log(n) / LOG1000\n    if r > 1.0:\n        r = 1.0\n    return 1.0 + (max_speed - 1.0) * r ** 1.5\n\n\ndef _swept(ax, ay, bx, by, p0x, p0y, p1x, p1y, r):\n    d0x = ax - p0x\n    d0y = ay - p0y\n    dvx = (bx - ax) - (p1x - p0x)\n    dvy = (by - ay) - (p1y - p0y)\n    a = dvx * dvx + dvy * dvy\n    b = 2.0 * (d0x * dvx + d0y * dvy)\n    c = d0x * d0x + d0y * d0y - r * r\n    if a < 1e-12:\n        return c <= 0.0\n    disc = b * b - 4.0 * a * c\n    if disc < 0.0:\n        return False\n    sq = math.sqrt(disc)\n    return (-b + sq) / (2.0 * a) >= 0.0 and (-b - sq) / (2.0 * a) <= 1.0\n\n\ndef _seg_pt(px, py, x1, y1, x2, y2):\n    wx = x2 - x1\n    wy = y2 - y1\n    l2 = wx * wx + wy * wy\n    if l2 == 0.0:\n        return math.hypot(px - x1, py - y1)\n    t = ((px - x1) * wx + (py - y1) * wy) / l2\n    if t < 0.0:\n        t = 0.0\n    elif t > 1.0:\n        t = 1.0\n    return math.hypot(px - x1 - t * wx, py - y1 - t * wy)\n\n\ndef make_state(obs):\n    """Build a sim state from a kaggle observation."""\n    comet_paths = {}\n    for g in obs.get("comets") or []:\n        pids = g.get("planet_ids", [])\n        paths = g.get("paths", [])\n        ci = g.get("path_index", 0)\n        for slot, cpid in enumerate(pids):\n            if slot < len(paths):\n                comet_paths[cpid] = (paths[slot], ci)\n    return {\n        "planets": [list(p) for p in obs["planets"]],\n        "fleets": [list(f) for f in obs["fleets"]],\n        "next_fleet_id": obs.get("next_fleet_id", 10000),\n        "step": obs["step"],\n        "angular_velocity": obs["angular_velocity"],\n        "initial": {p[0]: (p[2], p[3]) for p in (obs.get("initial_planets") or [])},\n        "comet_paths": comet_paths,\n        "comet_paths_step": obs["step"],\n    }\n\n\ndef clone_state(st):\n    return {\n        "planets": [list(p) for p in st["planets"]],\n        "fleets": [list(f) for f in st["fleets"]],\n        "next_fleet_id": st["next_fleet_id"],\n        "step": st["step"],\n        "angular_velocity": st["angular_velocity"],\n        "initial": st["initial"],\n        "comet_paths": st["comet_paths"],\n        "comet_paths_step": st.get("comet_paths_step", st["step"]),\n    }\n\n\ndef step(st, actions, max_speed=6.0, comet_speed=4.0):\n    """Advance one tick. actions: {player_id: [[from_id, angle, ships], ...]}"""\n    planets = st["planets"]\n    fleets = st["fleets"]\n    w = st["angular_velocity"]\n    cur_step = st["step"]\n\n    # comet expiry before launch (engine removes when path_index >= len)\n    rm = []\n    base = st.get("comet_paths_step", cur_step)\n    for p in planets:\n        cp = st["comet_paths"].get(p[0])\n        if cp is not None:\n            path, ci0 = cp\n            idx = ci0 + (cur_step - base)\n            if idx >= len(path):\n                rm.append(p[0])\n    if rm:\n        rms = set(rm)\n        st["planets"] = planets = [p for p in planets if p[0] not in rms]\n\n    # launches\n    by_id = {p[0]: p for p in planets}\n    for owner_id, moves in (actions or {}).items():\n        for mv in moves or []:\n            if len(mv) != 3:\n                continue\n            fid, ang, n = mv\n            n = int(n)\n            p = by_id.get(fid)\n            if p is None or p[1] != owner_id or n <= 0 or p[5] < n:\n                continue\n            p[5] -= n\n            sx = p[2] + math.cos(ang) * (p[4] + 0.1)\n            sy = p[3] + math.sin(ang) * (p[4] + 0.1)\n            fleets.append([st["next_fleet_id"], owner_id, sx, sy, ang, fid, n])\n            st["next_fleet_id"] += 1\n\n    # production\n    for p in planets:\n        if p[1] != -1:\n            p[5] += p[6]\n\n    # planet end-of-tick positions\n    paths = {}\n    expired_now = []\n    for p in planets:\n        cp = st["comet_paths"].get(p[0])\n        old = (p[2], p[3])\n        if cp is not None:\n            path, ci0 = cp\n            idx = ci0 + (cur_step - base) + 1\n            if idx >= len(path):\n                expired_now.append(p[0])\n                paths[p[0]] = (old, old, True)\n            else:\n                new = (path[idx][0], path[idx][1])\n                paths[p[0]] = (old, new, old[0] >= 0)\n            continue\n        init = st["initial"].get(p[0])\n        new = old\n        if init is not None:\n            dx = init[0] - CENTER\n            dy = init[1] - CENTER\n            r = math.hypot(dx, dy)\n            if r + p[4] < ROT_LIM:\n                a = math.atan2(dy, dx) + w * cur_step\n                new = (CENTER + r * math.cos(a), CENTER + r * math.sin(a))\n        paths[p[0]] = (old, new, True)\n\n    # fleet movement\n    removed = []\n    combat = {}\n    for f in fleets:\n        sp = fleet_speed(f[6], max_speed)\n        ox, oy = f[2], f[3]\n        f[2] += math.cos(f[4]) * sp\n        f[3] += math.sin(f[4]) * sp\n        hit = False\n        for p in planets:\n            pa = paths.get(p[0])\n            if pa is None or not pa[2]:\n                continue\n            (p0, p1, _) = pa\n            if _swept(ox, oy, f[2], f[3], p0[0], p0[1], p1[0], p1[1], p[4]):\n                combat.setdefault(p[0], []).append(f)\n                removed.append(f)\n                hit = True\n                break\n        if hit:\n            continue\n        if not (0.0 <= f[2] <= BOARD and 0.0 <= f[3] <= BOARD):\n            removed.append(f)\n            continue\n        if _seg_pt(CENTER, CENTER, ox, oy, f[2], f[3]) < SUN_R:\n            removed.append(f)\n\n    # apply movement\n    for p in planets:\n        pa = paths.get(p[0])\n        if pa is not None:\n            p[2], p[3] = pa[1]\n    if expired_now:\n        rms = set(expired_now)\n        st["planets"] = planets = [p for p in planets if p[0] not in rms]\n    rmset = {id(f) for f in removed}\n    st["fleets"] = [f for f in fleets if id(f) not in rmset]\n\n    # combat\n    by_id = {p[0]: p for p in planets}\n    for pid_, fl in combat.items():\n        p = by_id.get(pid_)\n        if p is None or not fl:\n            continue\n        sides = {}\n        for f in fl:\n            sides[f[1]] = sides.get(f[1], 0) + f[6]\n        g = sorted(sides.items(), key=lambda kv: kv[1], reverse=True)\n        top_o, top_n = g[0]\n        if len(g) > 1:\n            surv = top_n - g[1][1]\n            if top_n == g[1][1]:\n                surv = 0\n            so = top_o if surv > 0 else -1\n        else:\n            surv = top_n\n            so = top_o\n        if surv > 0:\n            if p[1] == so:\n                p[5] += surv\n            else:\n                p[5] -= surv\n                if p[5] < 0:\n                    p[1] = so\n                    p[5] = -p[5]\n\n    st["step"] = cur_step + 1\n    return st\n')
_ow_install_module('v31', '"""Orbit Wars agent.\n\nEngine-exact forward simulation + marginal-value greedy mission planner.\n\nPipeline each turn:\n  1. Predict every planet/comet position for the whole horizon (closed form,\n     matching the engine\'s rotation indexing incl. the step-0 quirk).\n  2. Simulate every in-flight fleet (all owners) with the engine\'s exact\n     swept-pair collision test -> landing events (planet, tick, owner, ships).\n  3. Build per-planet ownership/garrison timelines from those events.\n  4. Generate candidate missions (capture / defend / evacuate / funnel);\n     each is priced by the marginal change it causes in projected final\n     score differential (my ships - lambda * enemy ships at horizon).\n  5. Greedily commit the best missions, updating timelines after each.\n"""\n\nimport math\nimport time\n\nLOG1000 = math.log(1000.0)\nBOARD = 100.0\nCENTER = 50.0\nSUN_R = 10.0\nROT_LIM = 50.0\nEND_STEP = 498          # last step at which score is counted\nH_MAX = 110\n\n# tunables\nMARGIN_NEUTRAL = 2      # extra ships beyond computed requirement\nMARGIN_ENEMY = 4\nHOLD_OK_FALLBACK = True\nFUNNEL_MIN = 20         # min chunk size for rear->front transfers\nFUNNEL_FRac = 0.6\nPOS_BONUS = 0.10        # value per ship per 100 units of front-distance gained\nRESP_DISCOUNT = 0.55    # how strongly enemy counter-reinforcement discounts value\nMIN_V = 1.0             # do not commit missions below this marginal value\nMAX_MOVES = 16\n\n\ndef fleet_speed(n, max_speed):\n    if n <= 1:\n        return 1.0\n    r = math.log(n) / LOG1000\n    if r > 1.0:\n        r = 1.0\n    return 1.0 + (max_speed - 1.0) * r ** 1.5\n\n\ndef _swept_hit(ax, ay, bx, by, p0x, p0y, p1x, p1y, r):\n    """Engine\'s swept_pair_hit: fleet seg A->B vs planet chord P0->P1 within r."""\n    d0x = ax - p0x\n    d0y = ay - p0y\n    dvx = (bx - ax) - (p1x - p0x)\n    dvy = (by - ay) - (p1y - p0y)\n    a = dvx * dvx + dvy * dvy\n    b = 2.0 * (d0x * dvx + d0y * dvy)\n    c = d0x * d0x + d0y * d0y - r * r\n    if a < 1e-12:\n        return c <= 0.0\n    disc = b * b - 4.0 * a * c\n    if disc < 0.0:\n        return False\n    sq = math.sqrt(disc)\n    return (-b + sq) / (2.0 * a) >= 0.0 and (-b - sq) / (2.0 * a) <= 1.0\n\n\ndef _seg_sun_dist(x1, y1, x2, y2):\n    """Min distance from sun center to segment."""\n    wx = x2 - x1\n    wy = y2 - y1\n    l2 = wx * wx + wy * wy\n    px = CENTER - x1\n    py = CENTER - y1\n    if l2 == 0.0:\n        return math.hypot(px, py)\n    t = (px * wx + py * wy) / l2\n    if t < 0.0:\n        t = 0.0\n    elif t > 1.0:\n        t = 1.0\n    return math.hypot(px - t * wx, py - t * wy)\n\n\ndef _resolve_combat(owner, ships, arrivals):\n    """Engine combat: arrivals = [(owner, n), ...] hitting (owner, ships)."""\n    by = {}\n    for o, n in arrivals:\n        by[o] = by.get(o, 0) + n\n    groups = sorted(by.items(), key=lambda kv: kv[1], reverse=True)\n    top_o, top_n = groups[0]\n    if len(groups) > 1:\n        second = groups[1][1]\n        surv = top_n - second\n        if top_n == second:\n            surv = 0\n        surv_o = top_o if surv > 0 else -1\n    else:\n        surv = top_n\n        surv_o = top_o\n    if surv > 0:\n        if owner == surv_o:\n            ships += surv\n        else:\n            ships -= surv\n            if ships < 0:\n                owner = surv_o\n                ships = -ships\n    return owner, ships\n\n\ndef think(obs, cfg):\n    t_start = time.time()\n    step = obs["step"]\n    me = obs["player"]\n    max_speed = 6.0\n    comet_speed = 4.0\n    if cfg:\n        try:\n            max_speed = float(cfg.get("shipSpeed", 6.0) or 6.0)\n            comet_speed = float(cfg.get("cometSpeed", 4.0) or 4.0)\n        except Exception:\n            pass\n\n    remaining = END_STEP - step\n    if remaining <= 0:\n        return []\n    H = min(H_MAX, remaining)\n\n    # FFA: with 3 enemies the full-pessimism response gate (no pinning) is\n    # closer to truth — pinning assumes the one defender is also the only\n    # threat, which only holds in 1v1. NOTE: initial_planets owners are all\n    # -1 (engine snapshots before home assignment) — detect from live state.\n    ffa = me >= 2 or any(p[1] >= 2 for p in obs["planets"]) \\\n        or any(f[1] >= 2 for f in obs["fleets"])\n\n    overage = obs.get("remainingOverageTime", 60) or 60\n    budget = 0.72 if overage > 20 else (0.5 if overage > 8 else 0.3)\n    deadline = t_start + budget\n\n    planets_raw = obs["planets"]\n    fleets_raw = obs["fleets"]\n    comet_groups = obs.get("comets") or []\n    comet_id_set = set(obs.get("comet_planet_ids") or [])\n    w = obs["angular_velocity"]\n    initial = {p[0]: p for p in (obs.get("initial_planets") or [])}\n\n    NP = len(planets_raw)\n    pid = [0] * NP\n    owner = [0] * NP\n    pr = [0.0] * NP\n    pships = [0] * NP\n    pprod = [0] * NP\n    is_comet = [False] * NP\n\n    comet_path = {}\n    for g in comet_groups:\n        pids = g.get("planet_ids", [])\n        paths = g.get("paths", [])\n        ci = g.get("path_index", 0)\n        for slot, cpid in enumerate(pids):\n            if slot < len(paths):\n                comet_path[cpid] = (paths[slot], ci)\n\n    pos = []            # pos[i][k] = (x, y) for k = 0..H\n    dead_from = []      # tick at which comet expires (stays put that tick, gone after)\n    mv = []             # max per-tick movement (for quick-reject)\n    for i in range(NP):\n        p = planets_raw[i]\n        pid[i] = p[0]\n        owner[i] = p[1]\n        x0 = p[2]\n        y0 = p[3]\n        pr[i] = p[4]\n        pships[i] = p[5]\n        pprod[i] = p[6]\n        if p[0] in comet_path:\n            is_comet[i] = True\n            path, ci = comet_path[p[0]]\n            plen = len(path)\n            arr = []\n            last = (x0, y0)\n            for k in range(H + 1):\n                j = ci + k\n                if 0 <= j < plen:\n                    last = (path[j][0], path[j][1])\n                arr.append(last)\n            pos.append(arr)\n            dead_from.append(max(1, plen - ci))\n            mv.append(comet_speed + 0.2)\n        else:\n            ip = initial.get(p[0])\n            rotating = False\n            orad = 0.0\n            if ip is not None:\n                orad_i = math.hypot(ip[2] - CENTER, ip[3] - CENTER)\n                rotating = (orad_i + p[4]) < ROT_LIM\n            if rotating and w:\n                orad = math.hypot(x0 - CENTER, y0 - CENTER)\n                a0 = math.atan2(y0 - CENTER, x0 - CENTER)\n                arr = []\n                for k in range(H + 1):\n                    kk = k if step >= 1 else (k - 1 if k > 0 else 0)\n                    a = a0 + w * kk\n                    arr.append((CENTER + orad * math.cos(a),\n                                CENTER + orad * math.sin(a)))\n                pos.append(arr)\n                mv.append(orad * w + 0.05)\n            else:\n                pos.append([(x0, y0)] * (H + 1))\n                mv.append(0.0)\n            dead_from.append(H + 2)\n        if pships[i] < 0:\n            pships[i] = 0\n\n    rng_np = range(NP)\n\n    def fly(x, y, ang, n, start_k=0):\n        """Simulate a fleet; returns (planet_index, tick) on landing,\n        (-1, tick) if destroyed, (-2, H+1) if it outlives the horizon.\n        start_k > 0 simulates a launch that many ticks in the future\n        (orbits are deterministic, so the check is exact)."""\n        sp = fleet_speed(n, max_speed)\n        dx = math.cos(ang) * sp\n        dy = math.sin(ang) * sp\n        for k in range(start_k + 1, H + 1):\n            nx = x + dx\n            ny = y + dy\n            for i in rng_np:\n                if k > dead_from[i]:\n                    continue\n                ox, oy = pos[i][k - 1]\n                ddx = ox - x\n                ddy = oy - y\n                lim = sp + mv[i] + pr[i] + 0.7\n                if ddx * ddx + ddy * ddy > lim * lim:\n                    continue\n                qx, qy = pos[i][k]\n                if _swept_hit(x, y, nx, ny, ox, oy, qx, qy, pr[i]):\n                    return (i, k)\n            if nx < 0.0 or nx > BOARD or ny < 0.0 or ny > BOARD:\n                return (-1, k)\n            if _seg_sun_dist(x, y, nx, ny) < SUN_R:\n                return (-1, k)\n            x = nx\n            y = ny\n        return (-2, H + 1)\n\n    # ---- landing events from all in-flight fleets ----\n    events = [dict() for _ in rng_np]\n    for f in fleets_raw:\n        land, k = fly(f[2], f[3], f[4], f[6])\n        if land >= 0 and k < dead_from[land]:\n            events[land].setdefault(k, []).append((f[1], f[6]))\n\n    # ---- per-planet timeline simulation ----\n    def sim(i, mods=None, ships0=None):\n        """Returns (owner_at_H, ships_at_H, first_lost_tick, first_gain_tick).\n        owner -9 means the comet expired (everything lost)."""\n        ow = owner[i]\n        s = pships[i] if ships0 is None else ships0\n        evs = events[i]\n        df = dead_from[i]\n        prod = pprod[i]\n        first_lost = None\n        first_gain = None\n        was_me = ow == me\n        for k in range(1, H + 1):\n            if k >= df:\n                return (-9, 0, first_lost, first_gain)\n            if ow != -1:\n                s += prod\n            arr = evs.get(k)\n            m = mods.get(k) if mods else None\n            if arr or m:\n                lst = (list(arr) if arr else [])\n                if m:\n                    lst.extend(m)\n                ow2, s = _resolve_combat(ow, s, lst)\n                if ow2 != ow:\n                    if ow2 == me and first_gain is None:\n                        first_gain = k\n                    if ow == me and first_lost is None:\n                        first_lost = k\n                    ow = ow2\n        return (ow, s, first_lost, first_gain)\n\n    enemies = set()\n    for i in rng_np:\n        if owner[i] != -1 and owner[i] != me:\n            enemies.add(owner[i])\n    for f in fleets_raw:\n        if f[1] != me:\n            enemies.add(f[1])\n    lam = 1.0 if len(enemies) <= 1 else 0.55\n\n    # per-opponent denial weight: hurting the strongest enemy matters most,\n    # a dying enemy\'s holdings are barely worth denying (but still cheap to take)\n    enemy_strength = {}\n    for i in rng_np:\n        if owner[i] != -1 and owner[i] != me:\n            enemy_strength[owner[i]] = enemy_strength.get(owner[i], 0) + pships[i] + pprod[i] * 25\n    for f in fleets_raw:\n        if f[1] != me:\n            enemy_strength[f[1]] = enemy_strength.get(f[1], 0) + f[6]\n    max_str = max(enemy_strength.values()) if enemy_strength else 1\n    lam_by = {}\n    for o, s in enemy_strength.items():\n        lam_by[o] = lam * (0.25 + 0.75 * s / max_str) if len(enemies) > 1 else lam\n\n    tail = remaining - H  # production turns beyond the horizon\n\n    def tl_value(i, ow_H, s_H):\n        if ow_H == -9 or ow_H == -1:\n            return 0.0\n        extra = 0 if is_comet[i] else pprod[i] * tail\n        if ow_H == me:\n            return s_H + extra\n        return -lam_by.get(ow_H, lam) * (s_H + extra)\n\n    base_tl = [sim(i) for i in rng_np]\n    base_val = [tl_value(i, base_tl[i][0], base_tl[i][1]) for i in rng_np]\n\n    # full per-tick (owner, ships) tracks for pre-ranking against the\n    # *future* state at arrival (catches snipe windows the current state hides)\n    def track(i):\n        ow = owner[i]\n        s = pships[i]\n        evs = events[i]\n        df = dead_from[i]\n        prod = pprod[i]\n        ows = [ow] * (H + 1)\n        shs = [s] * (H + 1)\n        for k in range(1, H + 1):\n            if k >= df:\n                for j in range(k, H + 1):\n                    ows[j] = -9\n                    shs[j] = 0\n                break\n            if ow != -1:\n                s += prod\n            arr = evs.get(k)\n            if arr:\n                ow, s = _resolve_combat(ow, s, list(arr))\n            ows[k] = ow\n            shs[k] = s\n        return ows, shs\n\n    base_track = [track(i) for i in rng_np]\n\n    cur_ships = list(pships)   # mutated as missions are committed\n\n    my_idx = [i for i in rng_np if owner[i] == me]\n    enemy_idx = [i for i in rng_np if owner[i] != me and owner[i] != -1]\n\n    if not my_idx:\n        return []\n\n    # distance helper on current positions\n    def d0(i, j):\n        ax, ay = pos[i][0]\n        bx, by = pos[j][0]\n        return math.hypot(ax - bx, ay - by)\n\n    # front distance: distance to nearest enemy planet (for funneling)\n    def front_dist(i):\n        best = 200.0\n        for e in enemy_idx:\n            d = d0(i, e)\n            if d < best:\n                best = d\n        return best\n\n    def aim_and_validate(si, ti, n):\n        """Find launch angle hitting ti with n ships. Returns (angle, tick) or None."""\n        sx, sy = pos[si][0]\n        sp = fleet_speed(n, max_speed)\n        tx0, ty0 = pos[ti][0]\n        T = max(1.0, (math.hypot(tx0 - sx, ty0 - sy) - pr[ti] - pr[si]) / sp)\n        a = 0.0\n        for _ in range(3):\n            Tc = int(T + 0.5)\n            if Tc < 1:\n                Tc = 1\n            if Tc > H:\n                Tc = H\n            if Tc >= dead_from[ti]:\n                Tc = dead_from[ti] - 1\n                if Tc < 1:\n                    return None\n            tx, ty = pos[ti][Tc]\n            a = math.atan2(ty - sy, tx - sx)\n            T = max(1.0, (math.hypot(tx - sx, ty - sy) - pr[ti] - pr[si]) / sp)\n        for da in (0.0, 0.04, -0.04, 0.10, -0.10):\n            ang = a + da\n            lx = sx + math.cos(ang) * (pr[si] + 0.101)\n            ly = sy + math.sin(ang) * (pr[si] + 0.101)\n            land, k = fly(lx, ly, ang, n)\n            if land == ti and k < dead_from[ti]:\n                return (ang, k)\n        return None\n\n    def needed_for(ti, T, cap, want_hold):\n        """Minimal n arriving at T that ends with the planet mine (binary search).\n        If want_hold fails entirely, fall back to capture-at-T."""\n        def ok_hold(n):\n            ow, s, fl, fg = sim(ti, {T: [(me, n)]})\n            return ow == me\n        if ok_hold(cap):\n            lo, hi = 1, cap\n            while lo < hi:\n                mid = (lo + hi) // 2\n                if ok_hold(mid):\n                    hi = mid\n                else:\n                    lo = mid + 1\n            return lo\n        if not want_hold or not HOLD_OK_FALLBACK:\n            return None\n        def ok_cap(n):\n            ow, s, fl, fg = sim(ti, {T: [(me, n)]})\n            return fg is not None and fg <= T\n        if not ok_cap(cap):\n            return None\n        lo, hi = 1, cap\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if ok_cap(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n        return lo\n\n    def enemy_response(ti, T):\n        """Enemy ships that could plausibly reach ti before/around T."""\n        tot = 0\n        for e in enemy_idx:\n            if e == ti:\n                continue\n            eta = d0(e, ti) / 4.5\n            if eta <= T + 2:\n                tot += cur_ships[e]\n        return tot\n\n    src_val_cache = {}\n\n    def src_value(si, ships0):\n        key = (si, ships0)\n        v = src_val_cache.get(key)\n        if v is None:\n            ow, s, fl, fg = sim(si, None, ships0=ships0)\n            v = tl_value(si, ow, s)\n            src_val_cache[key] = v\n        return v\n\n    def eval_mission(si, ti, n_hint=None, funnel=False):\n        """Fully price a mission. Returns (V, n, angle, T) or None."""\n        avail = cur_ships[si]\n        if avail <= 0:\n            return None\n        contested = False\n        race_blocked = False\n        if funnel:\n            n = n_hint\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                return None\n            ang, T = av\n        else:\n            # initial guess for sizing\n            guess = pships[ti] + 8\n            if owner[ti] != -1 and owner[ti] != me:\n                guess += pprod[ti] * 15\n            if guess > avail:\n                guess = avail\n            if guess < 1:\n                guess = 1\n            av = aim_and_validate(si, ti, guess)\n            if av is None and guess * 2 <= avail:\n                # a bigger fleet is faster: different sweep timing can\n                # thread lanes that kill a slow fleet\n                guess = guess * 2\n                av = aim_and_validate(si, ti, guess)\n            if av is None:\n                eval_mission.rej = "aim"\n                return None\n            ang, T = av\n            need = needed_for(ti, T, avail, want_hold=True)\n            if need is None:\n                return None\n            if owner[ti] != -1 and owner[ti] != me:\n                # hard gate: an attack the defender can answer is a pure ship\n                # donation (ledger: 40-53% of production bled in lost attacks).\n                # Require beating garrison + everything they can deliver by T.\n                resp_full = 0\n                for e in enemy_idx:\n                    if e == ti:\n                        continue\n                    force = cur_ships[e] - 5\n                    if force <= 0:\n                        continue\n                    # pinning: a defender planet under threat from my nearby\n                    # garrisons can\'t strip itself to help — subtract the\n                    # largest single threat I project onto it\n                    pin = 0\n                    for m_i in (() if ffa else my_idx):\n                        if m_i == si:\n                            continue\n                        if d0(m_i, e) / 4.5 <= T + 4:\n                            t_force = cur_ships[m_i] - 5\n                            if t_force > pin:\n                                pin = t_force\n                    force -= int(0.8 * min(pin, force))\n                    if force <= 0:\n                        continue\n                    sp_e = fleet_speed(force, max_speed)\n                    eta_e = 1 + (d0(e, ti) - pr[ti] - pr[e]) / sp_e\n                    if eta_e <= T:\n                        resp_full += force\n                need += resp_full\n                if need > avail:\n                    return None\n            margin = MARGIN_ENEMY if owner[ti] != -1 and owner[ti] != me else MARGIN_NEUTRAL\n            race_blocked = False\n            if owner[ti] == -1:\n                # race-awareness: an equidistant enemy can launch the same\n                # turn we do (invisible to the forecast). Same-tick equal\n                # arrivals tie and BOTH die (engine rule) — require beating\n                # garrison + their plausible racing fleet, else look away.\n                e_eta = 1e9\n                e_force = 0\n                for e in enemy_idx:\n                    force = cur_ships[e] - 3\n                    if force <= 0:\n                        continue\n                    sp_e = fleet_speed(force, max_speed)\n                    eta_e = 1 + (d0(e, ti) - pr[ti] - pr[e]) / sp_e\n                    if eta_e < e_eta:\n                        e_eta = eta_e\n                        e_force = force\n                if e_eta <= T + 1:\n                    n_race = need + margin + min(e_force, need + margin)\n                    if n_race <= avail:\n                        margin += n_race - (need + margin)\n                    else:\n                        race_blocked = True\n            n = need + margin\n            # hold-aware sizing: a fresh capture with a tiny garrison is free\n            # food for counter-snipes; send enough to survive the plausible\n            # counter, or mark the mission contested (value discounted below)\n            contested = False\n            snipe_req = 0\n            for e in enemy_idx:\n                eta_e = d0(e, ti) / 4.5\n                if eta_e > T + 14:\n                    continue\n                arr_k = (T + 1) if eta_e <= T else int(eta_e) + 1\n                force = cur_ships[e]\n                if force > 45:\n                    force = 45\n                req = need + force - pprod[ti] * (arr_k - T) + 1\n                if req > snipe_req:\n                    snipe_req = req\n            if snipe_req > n:\n                if snipe_req <= avail:\n                    n = snipe_req\n                else:\n                    contested = True\n            if n > avail:\n                n = avail\n                if n < need:\n                    return None\n            # re-aim with the final size (speed changed)\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                return None\n            ang, T2 = av\n            if T2 != T:\n                need2 = needed_for(ti, T2, avail, want_hold=True)\n                if need2 is None:\n                    return None\n                if need2 + margin > n:\n                    n = min(avail, need2 + margin)\n                    if n < need2:\n                        return None\n                    av = aim_and_validate(si, ti, n)\n                    if av is None:\n                        return None\n                    ang, T2 = av\n                T = T2\n        ow2, s2, fl2, fg2 = sim(ti, {T: [(me, n)]})\n        dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n        dV_s = src_value(si, cur_ships[si] - n) - src_value(si, cur_ships[si])\n        V = dV_t + dV_s - 0.05 * T\n        if funnel:\n            gain = front_dist(si) - front_dist(ti)\n            V += POS_BONUS * n * gain / 100.0 * 10.0\n        elif owner[ti] != me:\n            if race_blocked and V > 0:\n                V *= 0.3\n            if contested and V > 0:\n                V *= 0.4\n            resp = enemy_response(ti, T)\n            if resp > 0:\n                # 1v1: a neutral is a race, not a defended position -> light\n                # discount. FFA: neutrals genuinely contested by 3 rivals.\n                if owner[ti] == -1 and len(enemies) <= 1:\n                    w_resp = 0.15\n                else:\n                    w_resp = RESP_DISCOUNT\n                V -= w_resp * min(resp, n)\n        return (V, n, ang, T)\n\n    # current target values (updated after commits)\n    cur_tgt_val = list(base_val)\n\n    # ---- candidate pair selection (crude pre-ranking) ----\n    pairs = []   # (priority, si, ti, kind)\n    for si in my_idx:\n        if cur_ships[si] <= 0:\n            continue\n        scored = []\n        for ti in rng_np:\n            if ti == si:\n                continue\n            d = d0(si, ti)\n            eta = d / 4.5\n            if owner[ti] == me:\n                if base_tl[ti][2] is not None:\n                    scored.append((4000 - d, ti))   # defend falling friend\n                continue\n            if eta >= remaining - 4:\n                continue\n            if is_comet[ti]:\n                if dead_from[ti] < eta + 6 or pships[ti] > 15:\n                    continue\n            # rank against the forecast state at estimated arrival, not now\n            ka = int(eta)\n            if ka > H:\n                ka = H\n            fo = base_track[ti][0][ka]\n            fs = base_track[ti][1][ka]\n            if fo == -9 or fo == me:\n                continue\n            denial = 1.0 + (lam_by.get(fo, lam) if fo != -1 else 0.0)\n            cost = fs + (pprod[ti] * eta * 0.5 if fo != -1 else 0)\n            crude = pprod[ti] * (remaining - eta) * denial - cost - 0.8 * d\n            # per-seat tie-break: identical agents otherwise race the same\n            # neutral every turn and same-tick ties kill both fleets forever\n            crude += ((pid[ti] * 7919 + me * 104729) % 13) * 0.03\n            if crude > 0:\n                scored.append((crude, ti))\n        scored.sort(reverse=True)\n        for crude, ti in scored[:12]:\n            pairs.append((crude, si, ti, "attack"))\n\n    # evacuation candidates: my planets about to fall, comets about to expire\n    safe_my = [i for i in my_idx if base_tl[i][2] is None and not is_comet[i]]\n    for si in my_idx:\n        doomed = base_tl[si][2] is not None and base_tl[si][2] <= 3\n        comet_exp = is_comet[si] and dead_from[si] <= 14\n        if not (doomed or comet_exp):\n            continue\n        if cur_ships[si] <= 0:\n            continue\n        targets = sorted(safe_my, key=lambda j: d0(si, j))[:2] if safe_my else []\n        for ti in targets:\n            pairs.append((5000.0, si, ti, "evac"))\n\n    pairs.sort(reverse=True)\n\n    relay_budget = [12]\n\n    def try_relay(si, ti, crude):\n        """Two-hop route to an unreachable target. Commits only hop 1\n        (ships to an own stepping-stone); later turns re-plan hop 2.\n        Returns a candidate row or None."""\n        d_direct = d0(si, ti)\n        best = None\n        for R in my_idx:\n            if R == si or R == ti or is_comet[R]:\n                continue\n            if base_tl[R][2] is not None:\n                continue\n            d1 = d0(si, R)\n            d2 = d0(R, ti)\n            if d1 < 6 or d1 + d2 > 1.7 * d_direct + 10:\n                continue\n            if best is None or d1 + d2 < best[1]:\n                best = (R, d1 + d2, d2)\n        if best is None:\n            return None\n        R, d_tot, d2 = best\n        # size for the target\'s forecast state at total ETA\n        eta_tot = d_tot / 4.0 + 3\n        ka = min(H, int(eta_tot))\n        fo = base_track[ti][0][ka]\n        fs = base_track[ti][1][ka]\n        if fo == me or fo == -9:\n            return None\n        need_rough = fs + (pprod[ti] * 8 if fo != -1 else 0) + MARGIN_NEUTRAL + 3\n        n = min(cur_ships[si], need_rough + 4)\n        if n < need_rough or n <= 0:\n            return None\n        av1 = aim_and_validate(si, R, n)\n        if av1 is None:\n            return None\n        ang1, T1 = av1\n        if T1 + d2 / 3.5 > H - 2:\n            return None\n        # verify hop 2 is actually flyable when the ships arrive at R\n        rx, ry = pos[R][min(T1, H)]\n        sp2 = fleet_speed(n, max_speed)\n        T2 = max(1.0, (d2 - pr[ti] - pr[R]) / sp2)\n        hop2_ok = False\n        for _ in range(3):\n            kc = min(H, T1 + int(T2 + 0.5))\n            if kc >= dead_from[ti]:\n                break\n            tx, ty = pos[ti][kc]\n            a2 = math.atan2(ty - ry, tx - rx)\n            lx = rx + math.cos(a2) * (pr[R] + 0.101)\n            ly = ry + math.sin(a2) * (pr[R] + 0.101)\n            land2, k2 = fly(lx, ly, a2, n, start_k=T1)\n            if land2 == ti and k2 < dead_from[ti]:\n                hop2_ok = True\n                T_tot = k2\n                break\n            T2 += 2\n        if not hop2_ok:\n            return None\n        # price as a delayed capture, discounted for re-plan uncertainty\n        ow2, s2, fl2, fg2 = sim(ti, {T_tot: [(me, n)]})\n        dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n        dV_s = src_value(si, cur_ships[si] - n) - src_value(si, cur_ships[si])\n        V = (dV_t * 0.75) + dV_s - 0.05 * T_tot\n        if V < MIN_V:\n            return None\n        return [V, si, R, n, ang1, T1, "relay"]\n\n    # ---- full evaluation of top candidates ----\n    cands = []\n    for crude, si, ti, kind in pairs[:90]:\n        if time.time() > deadline:\n            break\n        if kind == "evac":\n            n = cur_ships[si]\n            if n <= 0:\n                continue\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                continue\n            ang, T = av\n            # value: ships rescued (they\'d die otherwise)\n            ow2, s2, _, _ = sim(ti, {T: [(me, n)]})\n            dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n            dV_s = src_value(si, 0) - src_value(si, n)\n            V = dV_t + dV_s\n            if is_comet[si]:\n                V += n * 0.5    # urgency bonus: comet expiry is a hard loss\n            cands.append([V, si, ti, n, ang, T, kind])\n        else:\n            eval_mission.rej = None\n            r = eval_mission(si, ti)\n            if r is not None:\n                V, n, ang, T = r\n                cands.append([V, si, ti, n, ang, T, kind])\n            elif eval_mission.rej == "aim" and relay_budget[0] > 0:\n                # no direct line (sun / sweeping orbiters): relay through an\n                # own stepping-stone planet; hop 2 is verified at its actual\n                # future launch tick, which is exact for deterministic orbits\n                relay_budget[0] -= 1\n                rc = try_relay(si, ti, crude)\n                if rc is not None:\n                    cands.append(rc)\n\n    # funnel candidates: big garrisons far from the front shuttle forward\n    if remaining > 60 and len(safe_my) >= 2:\n        fronts = sorted(safe_my, key=front_dist)\n        front_set = fronts[:max(1, len(fronts) // 3)]\n        for si in safe_my:\n            if si in front_set or cur_ships[si] < FUNNEL_MIN * 2:\n                continue\n            n = int(cur_ships[si] * FUNNEL_FRac)\n            if n < FUNNEL_MIN:\n                continue\n            best_t = None\n            best_d = 1e9\n            for ti in front_set:\n                d = d0(si, ti)\n                if d < best_d:\n                    best_d = d\n                    best_t = ti\n            if best_t is None:\n                continue\n            r = eval_mission(si, best_t, n_hint=n, funnel=True)\n            if r is not None:\n                V, n2, ang, T = r\n                cands.append([V, si, best_t, n2, ang, T, "funnel"])\n\n    # ---- greedy commit loop ----\n    moves = []\n    committed_ship_count = {}\n    for _round in range(MAX_MOVES):\n        if not cands or time.time() > deadline:\n            break\n        cands.sort(key=lambda c: c[0], reverse=True)\n        best = cands[0]\n        V, si, ti, n, ang, T, kind = best\n        if V < MIN_V:\n            break\n        # re-verify against current (post-commit) state\n        if n > cur_ships[si]:\n            if kind in ("funnel", "relay") and cur_ships[si] >= 10:\n                n = cur_ships[si]\n                best[3] = n\n            else:\n                cands.pop(0)\n                continue\n        if kind not in ("evac", "funnel", "relay"):\n            r = eval_mission(si, ti)\n            if r is None:\n                cands.pop(0)\n                continue\n            V2, n2, ang2, T2 = r\n            if V2 < MIN_V:\n                cands.pop(0)\n                continue\n            if V2 < V - 1e-9:\n                best[0] = V2\n                best[3] = n2\n                best[4] = ang2\n                best[5] = T2\n                continue   # re-sort and reconsider\n            n, ang, T = n2, ang2, T2\n        # commit\n        moves.append([pid[si], float(ang), int(n)])\n        committed_ship_count[si] = committed_ship_count.get(si, 0) + n\n        cur_ships[si] -= n\n        events[ti].setdefault(T, []).append((me, n))\n        ow2, s2, fl2, fg2 = sim(ti)\n        cur_tgt_val[ti] = tl_value(ti, ow2, s2)\n        src_val_cache.clear()\n        cands.pop(0)\n        # drop other candidates aimed at the same target (will be re-derived next turn)\n        cands = [c for c in cands if c[2] != ti or c[6] == "evac"]\n\n    # final dump: doomed planets / expiring comets send any leftovers\n    for si in my_idx:\n        left = cur_ships[si]\n        if left <= 0:\n            continue\n        doomed = base_tl[si][2] is not None and base_tl[si][2] <= 2\n        comet_exp = is_comet[si] and dead_from[si] <= 3\n        if not (doomed or comet_exp):\n            continue\n        for ti in sorted(safe_my, key=lambda j: d0(si, j))[:3]:\n            if ti == si:\n                continue\n            av = aim_and_validate(si, ti, left)\n            if av is not None:\n                moves.append([pid[si], float(av[0]), int(left)])\n                cur_ships[si] = 0\n                break\n\n    return moves\n\n\ndef agent(obs, config=None):\n    try:\n        return think(obs, config)\n    except Exception:\n        return []\n')
_ow_install_module('v62_base', '"""Orbit Wars agent.\n\nEngine-exact forward simulation + marginal-value greedy mission planner.\n\nPipeline each turn:\n  1. Predict every planet/comet position for the whole horizon (closed form,\n     matching the engine\'s rotation indexing incl. the step-0 quirk).\n  2. Simulate every in-flight fleet (all owners) with the engine\'s exact\n     swept-pair collision test -> landing events (planet, tick, owner, ships).\n  3. Build per-planet ownership/garrison timelines from those events.\n  4. Generate candidate missions (capture / defend / evacuate / funnel);\n     each is priced by the marginal change it causes in projected final\n     score differential (my ships - lambda * enemy ships at horizon).\n  5. Greedily commit the best missions, updating timelines after each.\n"""\n\nimport math\nimport time\n\nLOG1000 = math.log(1000.0)\nBOARD = 100.0\nCENTER = 50.0\nSUN_R = 10.0\nROT_LIM = 50.0\nEND_STEP = 498          # last step at which score is counted\nH_MAX = 110\n\n# tunables\nMARGIN_NEUTRAL = 2      # extra ships beyond computed requirement\nMARGIN_ENEMY = 4\nHOLD_OK_FALLBACK = True\nFUNNEL_MIN = 20         # min chunk size for rear->front transfers\nFUNNEL_FRac = 0.9\nPOS_BONUS = 0.10        # value per ship per 100 units of front-distance gained\nRESP_DISCOUNT = 0.55    # how strongly enemy counter-reinforcement discounts value\nMIN_V = 1.0             # do not commit missions below this marginal value\nMAX_MOVES = 16\nLOW_PICKOFF_MAX_TARGET_SHIPS = 8\nLOW_PICKOFF_MAX_TARGET_PROD = 3\nLOW_PICKOFF_MAX_ETA = 5\nLOW_PICKOFF_SOURCE_RESERVE = 12\n\n\ndef fleet_speed(n, max_speed):\n    if n <= 1:\n        return 1.0\n    r = math.log(n) / LOG1000\n    if r > 1.0:\n        r = 1.0\n    return 1.0 + (max_speed - 1.0) * r ** 1.5\n\n\ndef _swept_hit(ax, ay, bx, by, p0x, p0y, p1x, p1y, r):\n    """Engine\'s swept_pair_hit: fleet seg A->B vs planet chord P0->P1 within r."""\n    d0x = ax - p0x\n    d0y = ay - p0y\n    dvx = (bx - ax) - (p1x - p0x)\n    dvy = (by - ay) - (p1y - p0y)\n    a = dvx * dvx + dvy * dvy\n    b = 2.0 * (d0x * dvx + d0y * dvy)\n    c = d0x * d0x + d0y * d0y - r * r\n    if a < 1e-12:\n        return c <= 0.0\n    disc = b * b - 4.0 * a * c\n    if disc < 0.0:\n        return False\n    sq = math.sqrt(disc)\n    return (-b + sq) / (2.0 * a) >= 0.0 and (-b - sq) / (2.0 * a) <= 1.0\n\n\ndef _seg_sun_dist(x1, y1, x2, y2):\n    """Min distance from sun center to segment."""\n    wx = x2 - x1\n    wy = y2 - y1\n    l2 = wx * wx + wy * wy\n    px = CENTER - x1\n    py = CENTER - y1\n    if l2 == 0.0:\n        return math.hypot(px, py)\n    t = (px * wx + py * wy) / l2\n    if t < 0.0:\n        t = 0.0\n    elif t > 1.0:\n        t = 1.0\n    return math.hypot(px - t * wx, py - t * wy)\n\n\ndef _resolve_combat(owner, ships, arrivals):\n    """Engine combat: arrivals = [(owner, n), ...] hitting (owner, ships)."""\n    by = {}\n    for o, n in arrivals:\n        by[o] = by.get(o, 0) + n\n    groups = sorted(by.items(), key=lambda kv: kv[1], reverse=True)\n    top_o, top_n = groups[0]\n    if len(groups) > 1:\n        second = groups[1][1]\n        surv = top_n - second\n        if top_n == second:\n            surv = 0\n        surv_o = top_o if surv > 0 else -1\n    else:\n        surv = top_n\n        surv_o = top_o\n    if surv > 0:\n        if owner == surv_o:\n            ships += surv\n        else:\n            ships -= surv\n            if ships < 0:\n                owner = surv_o\n                ships = -ships\n    return owner, ships\n\n\ndef think(obs, cfg):\n    t_start = time.time()\n    step = obs["step"]\n    me = obs["player"]\n    max_speed = 6.0\n    comet_speed = 4.0\n    if cfg:\n        try:\n            max_speed = float(cfg.get("shipSpeed", 6.0) or 6.0)\n            comet_speed = float(cfg.get("cometSpeed", 4.0) or 4.0)\n        except Exception:\n            pass\n\n    remaining = END_STEP - step\n    if remaining <= 0:\n        return []\n    H = min(H_MAX, remaining)\n\n    # FFA: with 3 enemies the full-pessimism response gate (no pinning) is\n    # closer to truth — pinning assumes the one defender is also the only\n    # threat, which only holds in 1v1. NOTE: initial_planets owners are all\n    # -1 (engine snapshots before home assignment) — detect from live state.\n    ffa = me >= 2 or any(p[1] >= 2 for p in obs["planets"]) \\\n        or any(f[1] >= 2 for f in obs["fleets"])\n    # endgame: elites never go quiet (launch rate constant through t=498,\n    # final-10-tick source drains); late captures still win differential\n    endgame = remaining <= 68\n\n    overage = obs.get("remainingOverageTime", 60) or 60\n    budget = 0.72 if overage > 20 else (0.5 if overage > 8 else 0.3)\n    deadline = t_start + budget\n\n    planets_raw = obs["planets"]\n    fleets_raw = obs["fleets"]\n    comet_groups = obs.get("comets") or []\n    comet_id_set = set(obs.get("comet_planet_ids") or [])\n    w = obs["angular_velocity"]\n    initial = {p[0]: p for p in (obs.get("initial_planets") or [])}\n\n    NP = len(planets_raw)\n    pid = [0] * NP\n    owner = [0] * NP\n    pr = [0.0] * NP\n    pships = [0] * NP\n    pprod = [0] * NP\n    is_comet = [False] * NP\n\n    comet_path = {}\n    for g in comet_groups:\n        pids = g.get("planet_ids", [])\n        paths = g.get("paths", [])\n        ci = g.get("path_index", 0)\n        for slot, cpid in enumerate(pids):\n            if slot < len(paths):\n                comet_path[cpid] = (paths[slot], ci)\n\n    pos = []            # pos[i][k] = (x, y) for k = 0..H\n    dead_from = []      # tick at which comet expires (stays put that tick, gone after)\n    mv = []             # max per-tick movement (for quick-reject)\n    for i in range(NP):\n        p = planets_raw[i]\n        pid[i] = p[0]\n        owner[i] = p[1]\n        x0 = p[2]\n        y0 = p[3]\n        pr[i] = p[4]\n        pships[i] = p[5]\n        pprod[i] = p[6]\n        if p[0] in comet_path:\n            is_comet[i] = True\n            path, ci = comet_path[p[0]]\n            plen = len(path)\n            arr = []\n            last = (x0, y0)\n            for k in range(H + 1):\n                j = ci + k\n                if 0 <= j < plen:\n                    last = (path[j][0], path[j][1])\n                arr.append(last)\n            pos.append(arr)\n            dead_from.append(max(1, plen - ci))\n            mv.append(comet_speed + 0.2)\n        else:\n            ip = initial.get(p[0])\n            rotating = False\n            orad = 0.0\n            if ip is not None:\n                orad_i = math.hypot(ip[2] - CENTER, ip[3] - CENTER)\n                rotating = (orad_i + p[4]) < ROT_LIM\n            if rotating and w:\n                orad = math.hypot(x0 - CENTER, y0 - CENTER)\n                a0 = math.atan2(y0 - CENTER, x0 - CENTER)\n                arr = []\n                for k in range(H + 1):\n                    kk = k if step >= 1 else (k - 1 if k > 0 else 0)\n                    a = a0 + w * kk\n                    arr.append((CENTER + orad * math.cos(a),\n                                CENTER + orad * math.sin(a)))\n                pos.append(arr)\n                mv.append(orad * w + 0.05)\n            else:\n                pos.append([(x0, y0)] * (H + 1))\n                mv.append(0.0)\n            dead_from.append(H + 2)\n        if pships[i] < 0:\n            pships[i] = 0\n\n    rng_np = range(NP)\n\n    def fly(x, y, ang, n, start_k=0):\n        """Simulate a fleet; returns (planet_index, tick) on landing,\n        (-1, tick) if destroyed, (-2, H+1) if it outlives the horizon.\n        start_k > 0 simulates a launch that many ticks in the future\n        (orbits are deterministic, so the check is exact)."""\n        sp = fleet_speed(n, max_speed)\n        dx = math.cos(ang) * sp\n        dy = math.sin(ang) * sp\n        for k in range(start_k + 1, H + 1):\n            nx = x + dx\n            ny = y + dy\n            for i in rng_np:\n                if k > dead_from[i]:\n                    continue\n                ox, oy = pos[i][k - 1]\n                ddx = ox - x\n                ddy = oy - y\n                lim = sp + mv[i] + pr[i] + 0.7\n                if ddx * ddx + ddy * ddy > lim * lim:\n                    continue\n                qx, qy = pos[i][k]\n                if _swept_hit(x, y, nx, ny, ox, oy, qx, qy, pr[i]):\n                    return (i, k)\n            if nx < 0.0 or nx > BOARD or ny < 0.0 or ny > BOARD:\n                return (-1, k)\n            if _seg_sun_dist(x, y, nx, ny) < SUN_R:\n                return (-1, k)\n            x = nx\n            y = ny\n        return (-2, H + 1)\n\n    # ---- landing events from all in-flight fleets ----\n    events = [dict() for _ in rng_np]\n    for f in fleets_raw:\n        land, k = fly(f[2], f[3], f[4], f[6])\n        if land >= 0 and k < dead_from[land]:\n            events[land].setdefault(k, []).append((f[1], f[6]))\n\n    # ---- per-planet timeline simulation ----\n    def sim(i, mods=None, ships0=None):\n        """Returns (owner_at_H, ships_at_H, first_lost_tick, first_gain_tick).\n        owner -9 means the comet expired (everything lost)."""\n        ow = owner[i]\n        s = pships[i] if ships0 is None else ships0\n        evs = events[i]\n        df = dead_from[i]\n        prod = pprod[i]\n        first_lost = None\n        first_gain = None\n        was_me = ow == me\n        for k in range(1, H + 1):\n            if k >= df:\n                return (-9, 0, first_lost, first_gain)\n            if ow != -1:\n                s += prod\n            arr = evs.get(k)\n            m = mods.get(k) if mods else None\n            if arr or m:\n                lst = (list(arr) if arr else [])\n                if m:\n                    lst.extend(m)\n                ow2, s = _resolve_combat(ow, s, lst)\n                if ow2 != ow:\n                    if ow2 == me and first_gain is None:\n                        first_gain = k\n                    if ow == me and first_lost is None:\n                        first_lost = k\n                    ow = ow2\n        return (ow, s, first_lost, first_gain)\n\n    enemies = set()\n    for i in rng_np:\n        if owner[i] != -1 and owner[i] != me:\n            enemies.add(owner[i])\n    for f in fleets_raw:\n        if f[1] != me:\n            enemies.add(f[1])\n    lam = 1.0 if len(enemies) <= 1 else 0.55\n\n    # per-opponent denial weight: hurting the strongest enemy matters most,\n    # a dying enemy\'s holdings are barely worth denying (but still cheap to take)\n    enemy_strength = {}\n    for i in rng_np:\n        if owner[i] != -1 and owner[i] != me:\n            enemy_strength[owner[i]] = enemy_strength.get(owner[i], 0) + pships[i] + pprod[i] * 25\n    for f in fleets_raw:\n        if f[1] != me:\n            enemy_strength[f[1]] = enemy_strength.get(f[1], 0) + f[6]\n    max_str = max(enemy_strength.values()) if enemy_strength else 1\n    lam_by = {}\n    for o, s in enemy_strength.items():\n        lam_by[o] = lam * (0.25 + 0.75 * s / max_str) if len(enemies) > 1 else lam\n\n    tail = remaining - H  # production turns beyond the horizon\n\n    def tl_value(i, ow_H, s_H):\n        if ow_H == -9 or ow_H == -1:\n            return 0.0\n        extra = 0 if is_comet[i] else pprod[i] * tail\n        if ow_H == me:\n            return s_H + extra\n        return -lam_by.get(ow_H, lam) * (s_H + extra)\n\n    base_tl = [sim(i) for i in rng_np]\n    base_val = [tl_value(i, base_tl[i][0], base_tl[i][1]) for i in rng_np]\n\n    # full per-tick (owner, ships) tracks for pre-ranking against the\n    # *future* state at arrival (catches snipe windows the current state hides)\n    def track(i):\n        ow = owner[i]\n        s = pships[i]\n        evs = events[i]\n        df = dead_from[i]\n        prod = pprod[i]\n        ows = [ow] * (H + 1)\n        shs = [s] * (H + 1)\n        for k in range(1, H + 1):\n            if k >= df:\n                for j in range(k, H + 1):\n                    ows[j] = -9\n                    shs[j] = 0\n                break\n            if ow != -1:\n                s += prod\n            arr = evs.get(k)\n            if arr:\n                ow, s = _resolve_combat(ow, s, list(arr))\n            ows[k] = ow\n            shs[k] = s\n        return ows, shs\n\n    base_track = [track(i) for i in rng_np]\n\n    cur_ships = list(pships)   # mutated as missions are committed\n\n    my_idx = [i for i in rng_np if owner[i] == me]\n    enemy_idx = [i for i in rng_np if owner[i] != me and owner[i] != -1]\n\n    if not my_idx:\n        return []\n\n    my_score_now = 0\n    enemy_score_now = 0\n    my_prod_now = 0\n    enemy_prod_now = 0\n    my_planets_now = 0\n    enemy_planets_now = 0\n    for i in rng_np:\n        if owner[i] == me:\n            my_score_now += pships[i]\n            my_prod_now += pprod[i]\n            my_planets_now += 1\n        elif owner[i] != -1:\n            enemy_score_now += pships[i]\n            enemy_prod_now += pprod[i]\n            enemy_planets_now += 1\n    for f in fleets_raw:\n        if f[1] == me:\n            my_score_now += f[6]\n        else:\n            enemy_score_now += f[6]\n    pressure_safe = (\n        my_score_now >= enemy_score_now\n        and my_prod_now >= enemy_prod_now\n        and my_planets_now >= enemy_planets_now\n    )\n\n    # distance helper on current positions\n    def d0(i, j):\n        ax, ay = pos[i][0]\n        bx, by = pos[j][0]\n        return math.hypot(ax - bx, ay - by)\n\n    # front distance: distance to nearest enemy planet (for funneling)\n    def front_dist(i):\n        best = 200.0\n        for e in enemy_idx:\n            d = d0(i, e)\n            if d < best:\n                best = d\n        return best\n\n    def aim_and_validate(si, ti, n):\n        """Find launch angle hitting ti with n ships. Returns (angle, tick) or None."""\n        sx, sy = pos[si][0]\n        sp = fleet_speed(n, max_speed)\n        tx0, ty0 = pos[ti][0]\n        T = max(1.0, (math.hypot(tx0 - sx, ty0 - sy) - pr[ti] - pr[si]) / sp)\n        a = 0.0\n        for _ in range(3):\n            Tc = int(T + 0.5)\n            if Tc < 1:\n                Tc = 1\n            if Tc > H:\n                Tc = H\n            if Tc >= dead_from[ti]:\n                Tc = dead_from[ti] - 1\n                if Tc < 1:\n                    return None\n            tx, ty = pos[ti][Tc]\n            a = math.atan2(ty - sy, tx - sx)\n            T = max(1.0, (math.hypot(tx - sx, ty - sy) - pr[ti] - pr[si]) / sp)\n        for da in (0.0, 0.04, -0.04, 0.10, -0.10):\n            ang = a + da\n            lx = sx + math.cos(ang) * (pr[si] + 0.101)\n            ly = sy + math.sin(ang) * (pr[si] + 0.101)\n            land, k = fly(lx, ly, ang, n)\n            if land == ti and k < dead_from[ti]:\n                return (ang, k)\n        return None\n\n    def needed_for(ti, T, cap, want_hold):\n        """Minimal n arriving at T that ends with the planet mine (binary search).\n        If want_hold fails entirely, fall back to capture-at-T."""\n        def ok_hold(n):\n            ow, s, fl, fg = sim(ti, {T: [(me, n)]})\n            return ow == me\n        if ok_hold(cap):\n            lo, hi = 1, cap\n            while lo < hi:\n                mid = (lo + hi) // 2\n                if ok_hold(mid):\n                    hi = mid\n                else:\n                    lo = mid + 1\n            return lo\n        if not want_hold or not HOLD_OK_FALLBACK:\n            return None\n        def ok_cap(n):\n            ow, s, fl, fg = sim(ti, {T: [(me, n)]})\n            return fg is not None and fg <= T\n        if not ok_cap(cap):\n            return None\n        lo, hi = 1, cap\n        while lo < hi:\n            mid = (lo + hi) // 2\n            if ok_cap(mid):\n                hi = mid\n            else:\n                lo = mid + 1\n        return lo\n\n    def enemy_response(ti, T):\n        """Enemy ships that could plausibly reach ti before/around T."""\n        tot = 0\n        for e in enemy_idx:\n            if e == ti:\n                continue\n            eta = d0(e, ti) / 4.5\n            if eta <= T + 2:\n                tot += cur_ships[e]\n        return tot\n\n    src_val_cache = {}\n\n    def src_value(si, ships0):\n        key = (si, ships0)\n        v = src_val_cache.get(key)\n        if v is None:\n            ow, s, fl, fg = sim(si, None, ships0=ships0)\n            v = tl_value(si, ow, s)\n            src_val_cache[key] = v\n        return v\n\n    def eval_mission(si, ti, n_hint=None, funnel=False):\n        """Fully price a mission. Returns (V, n, angle, T) or None."""\n        avail = cur_ships[si]\n        if avail <= 0:\n            return None\n        contested = False\n        race_blocked = False\n        if funnel:\n            n = n_hint\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                return None\n            ang, T = av\n        else:\n            # initial guess for sizing\n            guess = pships[ti] + 8\n            if owner[ti] != -1 and owner[ti] != me:\n                guess += pprod[ti] * 15\n            if guess > avail:\n                guess = avail\n            if guess < 1:\n                guess = 1\n            av = aim_and_validate(si, ti, guess)\n            if av is None and guess * 2 <= avail:\n                # a bigger fleet is faster: different sweep timing can\n                # thread lanes that kill a slow fleet\n                guess = guess * 2\n                av = aim_and_validate(si, ti, guess)\n            if av is None:\n                eval_mission.rej = "aim"\n                return None\n            ang, T = av\n            need = needed_for(ti, T, avail, want_hold=True)\n            if need is None:\n                return None\n            if owner[ti] != -1 and owner[ti] != me:\n                # hard gate: an attack the defender can answer is a pure ship\n                # donation (ledger: 40-53% of production bled in lost attacks).\n                # Require beating garrison + everything they can deliver by T.\n                resp_full = 0\n                for e in enemy_idx:\n                    if e == ti:\n                        continue\n                    force = cur_ships[e] - 5\n                    if force <= 0:\n                        continue\n                    # pinning: a defender planet under threat from my nearby\n                    # garrisons can\'t strip itself to help — subtract the\n                    # largest single threat I project onto it\n                    pin = 0\n                    for m_i in (() if ffa else my_idx):\n                        if m_i == si:\n                            continue\n                        if d0(m_i, e) / 4.5 <= T + 4:\n                            t_force = cur_ships[m_i] - 5\n                            if t_force > pin:\n                                pin = t_force\n                    force -= int(0.8 * min(pin, force))\n                    if force <= 0:\n                        continue\n                    sp_e = fleet_speed(force, max_speed)\n                    eta_e = 1 + (d0(e, ti) - pr[ti] - pr[e]) / sp_e\n                    if eta_e <= T:\n                        resp_full += force\n                need += resp_full\n                if need > avail:\n                    return None\n            margin = MARGIN_ENEMY if owner[ti] != -1 and owner[ti] != me else MARGIN_NEUTRAL\n            race_blocked = False\n            if owner[ti] == -1:\n                # race-awareness: an equidistant enemy can launch the same\n                # turn we do (invisible to the forecast). Same-tick equal\n                # arrivals tie and BOTH die (engine rule) — require beating\n                # garrison + their plausible racing fleet, else look away.\n                e_eta = 1e9\n                e_force = 0\n                for e in enemy_idx:\n                    force = cur_ships[e] - 3\n                    if force <= 0:\n                        continue\n                    sp_e = fleet_speed(force, max_speed)\n                    eta_e = 1 + (d0(e, ti) - pr[ti] - pr[e]) / sp_e\n                    if eta_e < e_eta:\n                        e_eta = eta_e\n                        e_force = force\n                if e_eta <= T + 1:\n                    n_race = need + margin + min(e_force, need + margin)\n                    if n_race <= avail:\n                        margin += n_race - (need + margin)\n                    else:\n                        race_blocked = True\n            n = need + margin\n            # hold-aware sizing: a fresh capture with a tiny garrison is free\n            # food for counter-snipes; send enough to survive the plausible\n            # counter, or mark the mission contested (value discounted below)\n            contested = False\n            snipe_req = 0\n            for e in enemy_idx:\n                eta_e = d0(e, ti) / 4.5\n                if eta_e > T + 14:\n                    continue\n                arr_k = (T + 1) if eta_e <= T else int(eta_e) + 1\n                force = cur_ships[e]\n                if force > 45:\n                    force = 45\n                req = need + force - pprod[ti] * (arr_k - T) + 1\n                if req > snipe_req:\n                    snipe_req = req\n            if snipe_req > n:\n                if snipe_req <= avail:\n                    n = snipe_req\n                else:\n                    contested = True\n            if n > avail:\n                n = avail\n                if n < need:\n                    return None\n            # re-aim with the final size (speed changed)\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                return None\n            ang, T2 = av\n            if T2 != T:\n                need2 = needed_for(ti, T2, avail, want_hold=True)\n                if need2 is None:\n                    return None\n                if need2 + margin > n:\n                    n = min(avail, need2 + margin)\n                    if n < need2:\n                        return None\n                    av = aim_and_validate(si, ti, n)\n                    if av is None:\n                        return None\n                    ang, T2 = av\n                T = T2\n            if (\n                opportunism\n                and not pressure_safe\n                and not ffa\n                and not endgame\n                and owner[ti] != -1\n                and owner[ti] != me\n                and pprod[ti] <= LOW_PICKOFF_MAX_TARGET_PROD\n                and pships[ti] <= LOW_PICKOFF_MAX_TARGET_SHIPS\n                and T <= LOW_PICKOFF_MAX_ETA\n                and cur_ships[si] - n < LOW_PICKOFF_SOURCE_RESERVE\n            ):\n                return None\n        ow2, s2, fl2, fg2 = sim(ti, {T: [(me, n)]})\n        dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n        dV_s = src_value(si, cur_ships[si] - n) - src_value(si, cur_ships[si])\n        V = dV_t + dV_s - (0.005 if endgame else 0.05) * T\n        if funnel:\n            gain = front_dist(si) - front_dist(ti)\n            V += POS_BONUS * n * gain / 100.0 * 10.0\n        elif owner[ti] != me:\n            if race_blocked and V > 0:\n                V *= 0.3\n            if owner[ti] != -1 and V > 0 and not ffa:\n                if opportunism:\n                    # elites cluster strikes within 10 ticks after the\n                    # opponent commits a big fleet; in FFA the third party\n                    # punishes the opportunist, so keep this 1v1 only\n                    V *= 1.6\n                elif pressure_safe:\n                    # Public 2p replay profiles still show substantially more\n                    # enemy-owned targeting than v46/v51, but v52\'s broad\n                    # version created down-flips after falling behind. Keep the\n                    # pressure bias only while already at least even.\n                    V *= 1.12\n            if contested and V > 0:\n                V *= 0.4\n            resp = enemy_response(ti, T)\n            if resp > 0:\n                # 1v1: a neutral is a race, not a defended position -> light\n                # discount. FFA: neutrals genuinely contested by 3 rivals.\n                if owner[ti] == -1 and len(enemies) <= 1:\n                    w_resp = 0.15\n                else:\n                    w_resp = RESP_DISCOUNT\n                V -= w_resp * min(resp, n)\n        return (V, n, ang, T)\n\n    # opportunism: a large enemy fleet just launched recently?\n    opportunism = False\n    id2i = {pid[i]: i for i in rng_np}\n    for f in fleets_raw:\n        if f[1] == me or f[6] < 80:\n            continue\n        srci = id2i.get(f[5])\n        if srci is None:\n            continue\n        sxp, syp = pos[srci][0]\n        age = math.hypot(f[2] - sxp, f[3] - syp) / fleet_speed(f[6], max_speed)\n        if age <= 10.0:\n            opportunism = True\n            break\n\n    # current target values (updated after commits)\n    cur_tgt_val = list(base_val)\n\n    # ---- candidate pair selection (crude pre-ranking) ----\n    pairs = []   # (priority, si, ti, kind)\n    for si in my_idx:\n        if cur_ships[si] <= 0:\n            continue\n        scored = []\n        for ti in rng_np:\n            if ti == si:\n                continue\n            d = d0(si, ti)\n            eta = d / 4.5\n            if owner[ti] == me:\n                if base_tl[ti][2] is not None:\n                    scored.append((4000 - d, ti))   # defend falling friend\n                continue\n            if eta >= remaining - 4:\n                continue\n            if is_comet[ti]:\n                if dead_from[ti] < eta + 6 or pships[ti] > 15:\n                    continue\n            # rank against the forecast state at estimated arrival, not now\n            ka = int(eta)\n            if ka > H:\n                ka = H\n            fo = base_track[ti][0][ka]\n            fs = base_track[ti][1][ka]\n            if fo == -9 or fo == me:\n                continue\n            denial = 1.0 + (lam_by.get(fo, lam) if fo != -1 else 0.0)\n            cost = fs + (pprod[ti] * eta * 0.5 if fo != -1 else 0)\n            crude = pprod[ti] * (remaining - eta) * denial - cost - 0.8 * d\n            # per-seat tie-break: identical agents otherwise race the same\n            # neutral every turn and same-tick ties kill both fleets forever\n            crude += ((pid[ti] * 7919 + me * 104729) % 13) * 0.03\n            if crude > 0:\n                scored.append((crude, ti))\n        scored.sort(reverse=True)\n        for crude, ti in scored[:12]:\n            pairs.append((crude, si, ti, "attack"))\n\n    # evacuation candidates: my planets about to fall, comets about to expire\n    safe_my = [i for i in my_idx if base_tl[i][2] is None and not is_comet[i]]\n    for si in my_idx:\n        doomed = base_tl[si][2] is not None and base_tl[si][2] <= 3\n        comet_exp = is_comet[si] and dead_from[si] <= 14\n        if not (doomed or comet_exp):\n            continue\n        if cur_ships[si] <= 0:\n            continue\n        targets = sorted(safe_my, key=lambda j: d0(si, j))[:2] if safe_my else []\n        for ti in targets:\n            pairs.append((5000.0, si, ti, "evac"))\n\n    pairs.sort(reverse=True)\n\n    relay_budget = [12]\n\n    def try_relay(si, ti, crude):\n        """Two-hop route to an unreachable target. Commits only hop 1\n        (ships to an own stepping-stone); later turns re-plan hop 2.\n        Returns a candidate row or None."""\n        d_direct = d0(si, ti)\n        best = None\n        for R in my_idx:\n            if R == si or R == ti or is_comet[R]:\n                continue\n            if base_tl[R][2] is not None:\n                continue\n            d1 = d0(si, R)\n            d2 = d0(R, ti)\n            if d1 < 6 or d1 + d2 > 1.7 * d_direct + 10:\n                continue\n            if best is None or d1 + d2 < best[1]:\n                best = (R, d1 + d2, d2)\n        if best is None:\n            return None\n        R, d_tot, d2 = best\n        # size for the target\'s forecast state at total ETA\n        eta_tot = d_tot / 4.0 + 3\n        ka = min(H, int(eta_tot))\n        fo = base_track[ti][0][ka]\n        fs = base_track[ti][1][ka]\n        if fo == me or fo == -9:\n            return None\n        need_rough = fs + (pprod[ti] * 8 if fo != -1 else 0) + MARGIN_NEUTRAL + 3\n        n = min(cur_ships[si], need_rough + 4)\n        if n < need_rough or n <= 0:\n            return None\n        av1 = aim_and_validate(si, R, n)\n        if av1 is None:\n            return None\n        ang1, T1 = av1\n        if T1 + d2 / 3.5 > H - 2:\n            return None\n        # verify hop 2 is actually flyable when the ships arrive at R\n        rx, ry = pos[R][min(T1, H)]\n        sp2 = fleet_speed(n, max_speed)\n        T2 = max(1.0, (d2 - pr[ti] - pr[R]) / sp2)\n        hop2_ok = False\n        for _ in range(3):\n            kc = min(H, T1 + int(T2 + 0.5))\n            if kc >= dead_from[ti]:\n                break\n            tx, ty = pos[ti][kc]\n            a2 = math.atan2(ty - ry, tx - rx)\n            lx = rx + math.cos(a2) * (pr[R] + 0.101)\n            ly = ry + math.sin(a2) * (pr[R] + 0.101)\n            land2, k2 = fly(lx, ly, a2, n, start_k=T1)\n            if land2 == ti and k2 < dead_from[ti]:\n                hop2_ok = True\n                T_tot = k2\n                break\n            T2 += 2\n        if not hop2_ok:\n            return None\n        # price as a delayed capture, discounted for re-plan uncertainty\n        ow2, s2, fl2, fg2 = sim(ti, {T_tot: [(me, n)]})\n        dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n        dV_s = src_value(si, cur_ships[si] - n) - src_value(si, cur_ships[si])\n        V = (dV_t * 0.75) + dV_s - 0.05 * T_tot\n        if V < MIN_V:\n            return None\n        return [V, si, R, n, ang1, T1, "relay"]\n\n    # ---- full evaluation of top candidates ----\n    cands = []\n    for crude, si, ti, kind in pairs[:90]:\n        if time.time() > deadline:\n            break\n        if kind == "evac":\n            n = cur_ships[si]\n            if n <= 0:\n                continue\n            av = aim_and_validate(si, ti, n)\n            if av is None:\n                continue\n            ang, T = av\n            # value: ships rescued (they\'d die otherwise)\n            ow2, s2, _, _ = sim(ti, {T: [(me, n)]})\n            dV_t = tl_value(ti, ow2, s2) - cur_tgt_val[ti]\n            dV_s = src_value(si, 0) - src_value(si, n)\n            V = dV_t + dV_s\n            if is_comet[si]:\n                V += n * 0.5    # urgency bonus: comet expiry is a hard loss\n            cands.append([V, si, ti, n, ang, T, kind])\n        else:\n            eval_mission.rej = None\n            r = eval_mission(si, ti)\n            if r is not None:\n                V, n, ang, T = r\n                cands.append([V, si, ti, n, ang, T, kind])\n            elif eval_mission.rej == "aim" and relay_budget[0] > 0:\n                # no direct line (sun / sweeping orbiters): relay through an\n                # own stepping-stone planet; hop 2 is verified at its actual\n                # future launch tick, which is exact for deterministic orbits\n                relay_budget[0] -= 1\n                rc = try_relay(si, ti, crude)\n                if rc is not None:\n                    cands.append(rc)\n\n    # funnel candidates: big garrisons far from the front shuttle forward\n    if remaining > 60 and len(safe_my) >= 2:\n        fronts = sorted(safe_my, key=front_dist)\n        front_set = fronts[:max(1, len(fronts) // 3)]\n        for si in safe_my:\n            source_min = FUNNEL_MIN * (3 if ffa else 2)\n            if si in front_set or cur_ships[si] < source_min:\n                continue\n            best_t = None\n            best_d = 1e9\n            for ti in front_set:\n                d = d0(si, ti)\n                if d < best_d:\n                    best_d = d\n                    best_t = ti\n            if best_t is None:\n                continue\n            gain = front_dist(si) - front_dist(best_t)\n            min_gain = 24.0 if ffa else 14.0\n            if gain < min_gain:\n                continue\n            n = int(cur_ships[si] * FUNNEL_FRac)\n            if n < FUNNEL_MIN:\n                continue\n            r = eval_mission(si, best_t, n_hint=n, funnel=True)\n            if r is not None:\n                V, n2, ang, T = r\n                cands.append([V, si, best_t, n2, ang, T, "funnel"])\n\n    # ---- greedy commit loop ----\n    moves = []\n    committed_ship_count = {}\n    for _round in range(MAX_MOVES):\n        if not cands or time.time() > deadline:\n            break\n        cands.sort(key=lambda c: c[0], reverse=True)\n        best = cands[0]\n        V, si, ti, n, ang, T, kind = best\n        if V < (0.1 if endgame else MIN_V):\n            break\n        # re-verify against current (post-commit) state\n        if n > cur_ships[si]:\n            if kind in ("funnel", "relay") and cur_ships[si] >= 10:\n                n = cur_ships[si]\n                best[3] = n\n            else:\n                cands.pop(0)\n                continue\n        if kind not in ("evac", "funnel", "relay"):\n            r = eval_mission(si, ti)\n            if r is None:\n                cands.pop(0)\n                continue\n            V2, n2, ang2, T2 = r\n            if V2 < (0.1 if endgame else MIN_V):\n                cands.pop(0)\n                continue\n            if V2 < V - 1e-9:\n                best[0] = V2\n                best[3] = n2\n                best[4] = ang2\n                best[5] = T2\n                continue   # re-sort and reconsider\n            n, ang, T = n2, ang2, T2\n        # commit\n        moves.append([pid[si], float(ang), int(n)])\n        committed_ship_count[si] = committed_ship_count.get(si, 0) + n\n        cur_ships[si] -= n\n        events[ti].setdefault(T, []).append((me, n))\n        ow2, s2, fl2, fg2 = sim(ti)\n        cur_tgt_val[ti] = tl_value(ti, ow2, s2)\n        src_val_cache.clear()\n        cands.pop(0)\n        # drop other candidates aimed at the same target (will be re-derived next turn)\n        cands = [c for c in cands if c[2] != ti or c[6] == "evac"]\n\n    # final dump: doomed planets / expiring comets send any leftovers\n    for si in my_idx:\n        left = cur_ships[si]\n        if left <= 0:\n            continue\n        doomed = base_tl[si][2] is not None and base_tl[si][2] <= 2\n        comet_exp = is_comet[si] and dead_from[si] <= 3\n        if not (doomed or comet_exp):\n            continue\n        for ti in sorted(safe_my, key=lambda j: d0(si, j))[:3]:\n            if ti == si:\n                continue\n            av = aim_and_validate(si, ti, left)\n            if av is not None:\n                moves.append([pid[si], float(av[0]), int(left)])\n                cur_ships[si] = 0\n                break\n\n    return moves\n\n\ndef agent(obs, config=None):\n    try:\n        return think(obs, config)\n    except Exception:\n        return []\n')

# ---- entry agent source ----
"""v62: v40 rollout selection over v62_base.

Each turn, the base planner's move set M0 competes against perturbations:
  M_minus : M0 without its largest offensive mission
Each variant is rolled K ticks in the exact engine port with BOTH sides
running a per-tick defense reflex (threatened planets pull reinforcements)
and the opponent getting one full replan at k=0. Best evaluated branch plays.
"""
import math
import time

import v62_base as v37
import v31
import sim_engine as SE

END_STEP = 498
K_ROLL = 32
LOG1000 = math.log(1000.0)


def _fleet_speed(n):
    if n <= 1:
        return 1.0
    r = min(1.0, math.log(n) / LOG1000)
    return 1.0 + 5.0 * r ** 1.5


def _reflex(st, player):
    """Cheap defense reflex: for each owned planet with hostile inbound
    fleets (straight-line ETA <= 8), pull reinforcement from the nearest
    friendly planet with surplus, sized to the deficit."""
    planets = st["planets"]
    fleets = st["fleets"]
    mine = [p for p in planets if p[1] == player]
    if not mine:
        return []
    by_id = {p[0]: p for p in planets}
    threat = {}
    for f in fleets:
        if f[1] == player:
            continue
        # straight-line nearest owned planet along heading
        sp = _fleet_speed(f[6])
        best, bd = None, 1e9
        for p in mine:
            dx = p[2] - f[2]
            dy = p[3] - f[3]
            d = math.hypot(dx, dy)
            # heading alignment
            if d > 1e-6:
                align = (dx * math.cos(f[4]) + dy * math.sin(f[4])) / d
                if align > 0.95 and d / sp <= 8:
                    if d < bd:
                        bd, best = d, p
        if best is not None:
            threat[best[0]] = threat.get(best[0], 0) + f[6]
    moves = []
    for pid_, inc in threat.items():
        tgt = by_id.get(pid_)
        if tgt is None:
            continue
        deficit = inc - tgt[5] - tgt[6] * 3
        if deficit <= 0:
            continue
        donors = sorted((p for p in mine if p[0] != pid_ and p[5] > 12),
                        key=lambda p: math.hypot(p[2] - tgt[2], p[3] - tgt[3]))
        for d_p in donors[:1]:
            n = min(d_p[5] - 6, deficit + 4)
            if n < 6:
                continue
            ang = math.atan2(tgt[3] - d_p[3], tgt[2] - d_p[2])
            moves.append([d_p[0], float(ang), int(n)])
    return moves


def _evaluate(st, me):
    rem = max(0, END_STEP - st["step"])
    w = min(rem, 80)
    val = 0.0
    for p in st["planets"]:
        if p[1] == me:
            val += p[5] + p[6] * w
        elif p[1] != -1:
            val -= p[5] + p[6] * w
    for f in st["fleets"]:
        val += f[6] if f[1] == me else -f[6]
    return val


def _obs_from_state(st, player, base_obs):
    base = st.get("comet_paths_step", st["step"])
    groups = []
    cpids = []
    for pid_, (path, ci0) in st["comet_paths"].items():
        idx = ci0 + (st["step"] - base)
        if idx >= len(path):
            continue
        if not any(p[0] == pid_ for p in st["planets"]):
            continue
        groups.append({"planet_ids": [pid_], "paths": [path], "path_index": idx})
        cpids.append(pid_)
    return {
        "step": st["step"], "player": player,
        "planets": [list(p) for p in st["planets"]],
        "fleets": [list(f) for f in st["fleets"]],
        "angular_velocity": st["angular_velocity"],
        "initial_planets": base_obs.get("initial_planets") or [],
        "comets": groups, "comet_planet_ids": cpids,
        "next_fleet_id": st["next_fleet_id"],
        "remainingOverageTime": 20,
    }


def _rollout(base_obs, my_moves, me, deadline):
    st = SE.make_state(base_obs)
    players = {p[1] for p in st["planets"] if p[1] != -1}
    players |= {f[1] for f in st["fleets"]}
    opp_ids = [o for o in players if o != me]
    for k in range(K_ROLL):
        acts = {}
        if k == 0:
            acts[me] = my_moves
            for o in opp_ids:
                if time.time() < deadline:
                    try:
                        acts[o] = v31.think(_obs_from_state(st, o, base_obs), None)
                    except Exception:
                        acts[o] = []
        else:
            for pl in [me] + opp_ids:
                r = _reflex(st, pl)
                if r:
                    acts[pl] = acts.get(pl, []) + r
        SE.step(st, acts)
        if time.time() > deadline:
            break
    return _evaluate(st, me)


def agent(obs, config=None):
    t0 = time.time()
    try:
        me = obs.get("player", 0)
        overage = obs.get("remainingOverageTime", 60) or 60
        budget = 0.80 if overage > 20 else (0.45 if overage > 8 else 0.2)
        deadline = t0 + budget
        try:
            m0 = v37.think(obs, config)
        except Exception:
            m0 = []
        if not m0 or time.time() > deadline - 0.3:
            return m0
        variants = [m0]
        # M_minus: drop the largest mission
        if len(m0) >= 1:
            biggest = max(range(len(m0)), key=lambda i: m0[i][2])
            if m0[biggest][2] >= 25:
                variants.append([m for i, m in enumerate(m0) if i != biggest])
        if len(variants) == 1:
            return m0
        best_v, best_m = None, m0
        for mv in variants:
            if time.time() > deadline - 0.1:
                break
            v = _rollout(obs, mv, me, deadline)
            if best_v is None or v > best_v + 1e-9:
                best_v, best_m = v, mv
        return best_m
    except Exception:
        try:
            return v37.think(obs, config)
        except Exception:
            return []
